try {
  // ── SCHEDULE DATA ── (mirrors config/schedule.json)
  const SCHEDULE = {
    'Dr. Emily Chen': {
      specialty: 'Family Medicine',
      appointment_types: ['New Patient', 'Follow-up'],
      schedule: {
        monday:    { free: ['9:00 AM','10:30 AM','2:00 PM','3:30 PM'], booked: ['11:00 AM','1:00 PM'] },
        tuesday:   { free: ['8:30 AM','1:30 PM','4:00 PM'],            booked: ['10:00 AM','11:30 AM','2:30 PM'] },
        wednesday: { free: ['9:00 AM','11:00 AM','3:00 PM'],            booked: ['10:00 AM','2:00 PM','4:00 PM'] },
        thursday:  { free: ['8:30 AM','10:00 AM','2:30 PM'],            booked: ['9:30 AM','11:30 AM','1:00 PM','3:30 PM'] }
      }
    },
    'Dr. James Park': {
      specialty: 'Internal Medicine',
      appointment_types: ['New Patient', 'Follow-up', 'Consultation'],
      schedule: {
        tuesday:   { free: ['9:00 AM','11:00 AM','2:00 PM'],   booked: ['10:00 AM','1:00 PM','3:00 PM'] },
        wednesday: { free: ['8:30 AM','10:30 AM','3:30 PM'],   booked: ['9:30 AM','1:30 PM','4:00 PM'] },
        thursday:  { free: ['9:00 AM','1:00 PM','4:00 PM'],    booked: ['10:30 AM','11:30 AM','2:30 PM'] },
        friday:    { free: ['8:30 AM','10:00 AM','2:00 PM','3:30 PM'], booked: ['9:00 AM','11:30 AM'] }
      }
    },
    'Dr. Priya Sharma': {
      specialty: 'Pediatrics',
      appointment_types: ['New Patient', 'Well-Child Visit', 'Follow-up'],
      schedule: {
        monday:    { free: ['9:30 AM','11:00 AM','2:30 PM'],              booked: ['10:30 AM','1:00 PM','3:30 PM'] },
        wednesday: { free: ['8:30 AM','10:00 AM','1:30 PM','4:00 PM'],    booked: ['9:30 AM','3:00 PM'] },
        friday:    { free: ['9:00 AM','11:30 AM','2:00 PM'],              booked: ['10:00 AM','1:00 PM','3:00 PM'] }
      }
    },
    'Dr. Marcus Webb': {
      specialty: 'Orthopedics',
      appointment_types: ['New Patient', 'Follow-up', 'Post-Op'],
      schedule: {
        monday:   { free: ['10:00 AM','1:00 PM','3:00 PM'],    booked: ['9:00 AM','11:00 AM','2:00 PM'] },
        tuesday:  { free: ['8:30 AM','11:30 AM','3:30 PM'],    booked: ['9:30 AM','10:30 AM','1:30 PM'] },
        thursday: { free: ['9:00 AM','10:30 AM','2:00 PM','4:00 PM'], booked: ['11:30 AM','1:00 PM','3:00 PM'] }
      }
    }
  };

  const body = $json;
  const params = body.parameters || body;
  const rawDoctorName = (params.doctor_name || '').trim();
  const rawDay = (params.day_of_week || '').trim().toLowerCase();

  const results = [];

  for (const [doctorName, info] of Object.entries(SCHEDULE)) {
    // Filter by doctor if specified (case-insensitive partial match)
    if (rawDoctorName && !doctorName.toLowerCase().includes(rawDoctorName.toLowerCase())) continue;

    const days = rawDay ? [rawDay] : Object.keys(info.schedule);
    for (const day of days) {
      const dayData = info.schedule[day];
      if (!dayData) continue;
      for (const time of dayData.free) {
        results.push({
          doctor: doctorName,
          specialty: info.specialty,
          day: day.charAt(0).toUpperCase() + day.slice(1),
          time: time,
          appointment_types_available: info.appointment_types
        });
      }
    }
  }

  if (results.length === 0) {
    return [{ json: {
      available_slots: [],
      message: rawDoctorName
        ? `No available slots found for ${rawDoctorName}${rawDay ? ' on ' + rawDay : ''}.`
        : 'No available slots found for the requested criteria.',
      success: true
    }}];
  }

  return [{ json: { available_slots: results, total: results.length, success: true } }];
} catch (error) {
  return [{ json: { success: false, error: String(error) } }];
}

try {
  const body = $json;
  const payload = {
    call_id: body.call_id || body.conversation_id || ('call_' + Date.now()),
    outcome: body.outcome || (body.parameters && body.parameters.outcome) || 'UNKNOWN',
    patient_name: body.patient_name || (body.parameters && body.parameters.patient_name) || null,
    doctor_name: body.doctor_name || (body.parameters && body.parameters.doctor_name) || null,
    appointment_day: body.appointment_day || (body.parameters && body.parameters.appointment_day) || null,
    appointment_time: body.appointment_time || (body.parameters && body.parameters.appointment_time) || null,
    insurance: body.insurance || (body.parameters && body.parameters.insurance) || null,
    notes: body.notes || (body.parameters && body.parameters.notes) || null,
    transcript: body.transcript || [],
    duration_seconds: body.duration || body.duration_seconds || null,
    timestamp: new Date().toISOString()
  };
  return [{ json: payload }];
} catch (error) {
  return [{ json: { success: false, error: String(error), raw: $json } }];
}

try {
  const SCHEDULE = {
    'Dr. Emily Chen':  { specialty: 'Family Medicine',  days: ['Mon','Tue','Wed','Thu'] },
    'Dr. James Park':  { specialty: 'Internal Medicine', days: ['Tue','Wed','Thu','Fri'] },
    'Dr. Priya Sharma':{ specialty: 'Pediatrics',        days: ['Mon','Wed','Fri'] },
    'Dr. Marcus Webb': { specialty: 'Orthopedics',       days: ['Mon','Tue','Thu'] }
  };
  const overview = Object.entries(SCHEDULE).map(([name, info]) => ({
    doctor: name,
    specialty: info.specialty,
    available_days: info.days
  }));
  return [{ json: { doctors: overview, success: true } }];
} catch (error) {
  return [{ json: { success: false, error: String(error) } }];
}
